import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import FilterPanel from './components/FilterPanel';
import StatsPanel from './components/StatsPanel';
import DonorList from './components/DonorList';

const App = () => {
  const [donors, setDonors] = useState([]);
  const [filteredDonors, setFilteredDonors] = useState([]);
  const [filters, setFilters] = useState({ bloodGroup: '', city: '' });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch('https://jsonplaceholder.typicode.com/users')
      .then(response => response.json())
      .then(data => {
        const bloodGroups = ["A+", "A-", "B+", "B-", "AB+", "AB-", "O+", "O-"];
        const mappedDonors = data.map(user => ({
          id: user.id,
          name: user.name,
          city: user.address.city,
          bloodGroup: bloodGroups[Math.floor(Math.random() * bloodGroups.length)],
          available: Math.random() > 0.5
        }));
        setDonors(mappedDonors);
        setLoading(false);
      });
  }, []);

  useEffect(() => {
    let filtered = donors;
    if (filters.bloodGroup) {
      filtered = filtered.filter(donor => donor.bloodGroup === filters.bloodGroup);
    }
    setFilteredDonors(filtered);
  }, [donors, filters]);

  const handleFilterChange = (newFilters) => {
    setFilters(newFilters);
  };

  return (
    <div className="app">
      <Header />
      <FilterPanel filters={filters} onFilterChange={handleFilterChange} />
      {loading ? (
        <p>Loading donors...</p>
      ) : (
        <>
          <StatsPanel totalDonors={donors.length} filteredDonors={filteredDonors.length} />
          <DonorList donors={filteredDonors} />
        </>
      )}
    </div>
  );
};

export default App;
